interface ITitleMap {
  [key: string]: string
}

let lastUsedTableData: IDataHubItem[] = [] // 保存上次使用的 tableData
let oldUsedTableData: IDataHubItem[] = [] // 保存上次使用的 tableData
let oldSelectedCategory: string = '' // 记录上次选择的 currentSelectedCategory

const getStatistics = (
  datahubData: IDataHubItem[],
  newTableData: IDataHubItem[],
  targetKeys: string[],
  titleMap: ITitleMap,
  expandedKeys: string[],
  currentSelectedCategory: string = ''
): IBMSelectorData[] => {
  const result: IBMSelectorData[] = []

  let dataToUse: IDataHubItem[] = datahubData

  // 更新上次使用的 tableData 和 oldSelectedCategory
  if (currentSelectedCategory !== oldSelectedCategory) {
    dataToUse = oldUsedTableData // 更新 lastUsedTableData 为当前计算所用的 dataToUse
    lastUsedTableData = oldUsedTableData
  } else {
    dataToUse = lastUsedTableData
  }

  if (currentSelectedCategory === '') {
    dataToUse = datahubData
    console.log('getStatistics >> currentSelectedCategory is empty', datahubData.length, dataToUse.length)
  }

  console.log(
    'getStatistics >> dataToUse',
    currentSelectedCategory,
    oldSelectedCategory,
    currentSelectedCategory === oldSelectedCategory && lastUsedTableData.length > 0,
    lastUsedTableData.length,
    dataToUse.length
  )

  targetKeys.forEach((key) => {
    const valueCountMap = new Map<any, number>()

    // 根据 currentSelectedCategory 判断使用的数据集
    const dataForKey = currentSelectedCategory && key !== currentSelectedCategory ? newTableData : dataToUse

    // 统计数据
    dataForKey.forEach((item) => {
      const value = item[key]
      if (value !== undefined && value !== null) {
        valueCountMap.set(value, (valueCountMap.get(value) || 0) + 1)
      }
    })

    // 计算总数
    const totalItems = dataForKey.length

    // 构造返回格式
    const valueList = Array.from(valueCountMap.entries()).map(([value, number], index) => {
      return {
        id: `value${index + 1}`,
        name: value,
        number,
        percentage: (number / totalItems) * 100
      }
    })

    // 将结果加入到返回数组中
    result.push({
      name: key,
      title: titleMap[key],
      expanded: expandedKeys.includes(key),
      value: valueList
    })
  })

  oldSelectedCategory = currentSelectedCategory // 更新 lastSelectedCategory 为当前选择的分类
  oldUsedTableData = newTableData

  return result
}

interface FilterCondition {
  name: string
  value: any[]
}

function filterData(datahubData: IDataHubItem[], filterConditions: FilterCondition[]): IDataHubItem[] {
  return datahubData.filter((item) => {
    // 对每个过滤条件进行检查
    for (const condition of filterConditions) {
      const { name, value } = condition

      // 如果 value 数组为空或未提供，则跳过该条件
      if (value.length === 0) {
        // console.log(`filterData >> Skipping condition for ${name} as value array is empty.`);
        continue // 跳过当前条件，不影响数据项
      }

      // 检查当前项的对应字段值是否在过滤条件的值范围内
      if (!value.includes(item[name])) {
        return false // 如果某个条件不满足，则排除该数据项
      }
    }

    // 如果所有条件都满足，保留该数据项
    return true
  })
}
